return items.map(item => {
  const j = item.json || {};
  const attrs = j.attributes || {};

  // --- 1) Extract basic record metadata ---
  const sourceObject = attrs.type || null;
  const recordId = attrs.url
    ? attrs.url.split('/').pop()
    : (j.Id || null);

  // --- 2) Read phone values from possible source fields ---
  const phoneLead = j.Phone ?? j.body?.nomorlead ?? null;
  const phoneOpportunity = j.Phone__c ?? j.body?.nomoroppty ?? null;

  // --- 3) Prioritize Lead phone, then fall back to Opportunity phone ---
  const rawPhone = phoneLead || phoneOpportunity || null;

  // --- 4) Normalize phone into +62 format ---
  let cleanPhone = null;
  if (rawPhone) {
    let p = String(rawPhone).trim();

    // Remove all non-digit characters
    p = p.replace(/\D/g, "");

    // If the number starts with 0, convert it to Indonesia country code format
    if (p.startsWith("0")) {
      p = "62" + p.slice(1);
    }

    // If the number does not start with 62, prepend the Indonesia country code
    if (!p.startsWith("62")) {
      p = "62" + p;
    }

    cleanPhone = "+" + p;
  }

  // --- 5) Build a standardized output object ---
  item.json = {
    Source_Object: sourceObject,
    SF_Id: recordId,
    CreatedById: j.CreatedById,

    CreatedDate: j.CreatedDate ?? null,
    Name: j.Name ?? null,

    Phone: rawPhone,
    Clean_Phone: cleanPhone,
    Email: j.Email ?? null,

    LeadSource: j.LeadSource ?? null,

    Status: j.Status ?? null,        // Lead only
    StageName: j.StageName ?? null,  // Opportunity only

    OwnerId: j.OwnerId ?? null,
    AccountId: j.AccountId ?? null,
    Amount: j.Amount ?? null
  };

  return item;
});

let start = new Date($input.first().json.start_date);
const end = new Date($input.first().json.end_date);

const output = [];

const formatDate = (date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

while (start <= end) {
  let until = new Date(start);
  until.setDate(until.getDate() + 6);

  if (until > end) {
    until = new Date(end);
  }

  const sinceDate = formatDate(start);
  const untilDate = formatDate(until);

  output.push({
    since: sinceDate,
    until: untilDate,
    since_datetime: `${sinceDate}T00:00:00Z`,
    until_datetime: `${untilDate}T23:59:59Z`,
  });

  start.setDate(start.getDate() + 7);
}

return output.map(d => ({ json: d }));

